 1	import { TemplateModel, V1Template } from '@kubevirt-ui/kubevirt-api/console';
 2	import { useAccessReview } from '@openshift-console/dynamic-plugin-sdk';
 3	
 4	import { isCommonVMTemplate } from '../../utils/utils';
 5	
 6	/**
 7	 * This hook checks the user capabilities of editing templates in a namespace.
 8	 * Checks user permissions and template characteristics.
 9	 * The hook does not check if the user has permissions for that particular template
10	 * as this behavior would compromise performarce in pages were a lot of templates are involved like template list.
11	 * @param template template to check
12	 * @returns boolean value
13	 */
14	const useEditTemplateAccessReview = (
15	  template: V1Template,
16	): {
17	  hasEditPermission: boolean;
18	  isCommonTemplate: boolean;
19	  isLoading: boolean;
20	  isTemplateEditable: boolean;
21	} => {
22	  const isCommonTemplate = isCommonVMTemplate(template);
23	  const [canUpdateTemplate, canUpdateLoading] = useAccessReview({
24	    namespace: template?.metadata?.namespace,
25	    resource: TemplateModel.plural,
26	    verb: 'update',
27	  });
28	
29	  const [canPatchTemplate, canPatchLoading] = useAccessReview({
30	    namespace: template?.metadata?.namespace,
31	    resource: TemplateModel.plural,
32	    verb: 'patch',
33	  });
34	
35	  const hasEditPermission = canUpdateTemplate && canPatchTemplate;
36	
37	  if (!template || canUpdateLoading || canPatchLoading)
38	    return {
39	      hasEditPermission: false,
40	      isCommonTemplate,
41	      isLoading: true,
42	      isTemplateEditable: false,
43	    };
44	
45	  return {
46	    hasEditPermission,
47	    isCommonTemplate,
48	    isLoading: canUpdateLoading || canPatchLoading,
49	    isTemplateEditable: !isCommonTemplate && hasEditPermission,
50	  };
51	};
52	
53	export default useEditTemplateAccessReview;

